sql:
SELECT view_count
FROM product_views
WHERE product_id = 1;

external_knowledge:
; Best-selling products are those that generate the most revenue; 
; The top search terms are the most frequently used search terms to find a product, with a minimum usage count of 11; 
; Average rating is a measure of the product's quality based on user reviews, ranging from 1 to 5 stars.

sql:
SELECT product_id
FROM product_views
WHERE view_count > 50;

SELECT product_id, view_count
FROM product_views
ORDER BY view_count DESC;
